styles:
.business-text { padding: 0; margin: 0; height: 100%; }
.business-text-content { height: 100%; }
.alert-banner { display: flex; align-items: center; gap: 8px; padding: 0 16px; border-left: 4px solid var(--alert-color, var(--bt-accent)); background: var(--alert-bg, rgba(148,163,184,0.12)); color: var(--bt-text); height: 100%; box-sizing: border-box; overflow: hidden; }
.alert-banner__icon { font-size: 15px; flex-shrink: 0; color: var(--alert-color, var(--bt-accent)); }
.alert-banner__icon--ok { color: #10B981; }
.alert-banner__badge { display: inline-flex; align-items: center; padding: 2px 8px; border-radius: 10px; color: #fff; font-size: 11px; font-weight: 600; flex-shrink: 0; white-space: nowrap; }
.alert-banner__badge--critical { background: #DC2626; }
.alert-banner__badge--warning { background: #D97706; }
.alert-banner__text { color: var(--bt-text); font-size: 12px; flex: 1; min-width: 0; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
.alert-banner--ok { --alert-color: #10B981; --alert-bg: rgba(16,185,129,0.12); }
.alert-banner--ok .alert-banner__text { font-size: 13px; }
.alert-banner--loading { --alert-color: #94A3B8; --alert-bg: rgba(148,163,184,0.12); }
.alert-banner--loading .alert-banner__text { color: var(--bt-text-muted); font-size: 13px; }
